"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import {
  Users,
  CheckCircle2,
  Star,
  Briefcase,
  TrendingUp,
  ArrowUpRight,
  Clock,
  UserCog,
  XCircle,
} from "lucide-react";
import {
  defaultProviders,
  PROVIDERS_STORAGE_KEY,
  type Provider,
  type ProviderStatus,
} from "./provider-data";

const getInitials = (name: string) =>
  name
    .split(" ")
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase())
    .slice(0, 2)
    .join("");

const getStatusBadge = (status: ProviderStatus) => {
  const styles: Record<ProviderStatus, string> = {
    active: "bg-green-100 text-green-700 dark:bg-green-900/20 dark:text-green-400",
    inactive: "bg-gray-100 text-gray-700 dark:bg-gray-900/20 dark:text-gray-400",
    suspended: "bg-red-100 text-red-700 dark:bg-red-900/20 dark:text-red-400",
  };

  const icons: Record<ProviderStatus, typeof CheckCircle2> = {
    active: CheckCircle2,
    inactive: Clock,
    suspended: XCircle,
  };

  const Icon = icons[status];

  return (
    <Badge variant="outline" className={styles[status]}>
      <Icon className="mr-1 h-3 w-3" />
      {status.charAt(0).toUpperCase() + status.slice(1)}
    </Badge>
  );
};

const formatDate = (date: string) =>
  new Intl.DateTimeFormat(undefined, {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(new Date(date));

const ProvidersDashboard = () => {
  const [providers, setProviders] = useState<Provider[]>(defaultProviders);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const loadProviders = () => {
      const stored = localStorage.getItem(PROVIDERS_STORAGE_KEY);
      if (stored) {
        try {
          const parsed = JSON.parse(stored) as Provider[];
          if (Array.isArray(parsed) && parsed.length > 0) {
            setProviders(parsed);
          }
        } catch (error) {
          console.error("Failed to parse stored providers", error);
        }
      }
    };

    loadProviders();

    const handleStorage = (event: StorageEvent) => {
      if (event.key === PROVIDERS_STORAGE_KEY) {
        loadProviders();
      }
    };

    window.addEventListener("storage", handleStorage);
    return () => window.removeEventListener("storage", handleStorage);
  }, []);

  const {
    totalProviders,
    activeCount,
    inactiveCount,
    suspendedCount,
    averageRating,
    totalJobs,
  } = useMemo(() => {
    const total = providers.length;
    const active = providers.filter((provider) => provider.status === "active").length;
    const inactive = providers.filter((provider) => provider.status === "inactive").length;
    const suspended = providers.filter((provider) => provider.status === "suspended").length;
    const avg = total
      ? providers.reduce((sum, provider) => sum + provider.rating, 0) / total
      : 0;
    const jobs = providers.reduce((sum, provider) => sum + provider.completedJobs, 0);

    return {
      totalProviders: total,
      activeCount: active,
      inactiveCount: inactive,
      suspendedCount: suspended,
      averageRating: Number(avg.toFixed(1)),
      totalJobs: jobs,
    };
  }, [providers]);

  const activeRate = totalProviders ? Math.round((activeCount / totalProviders) * 100) : 0;
  const suspendedRate = totalProviders ? Math.round((suspendedCount / totalProviders) * 100) : 0;

  const stats = useMemo(
    () => [
      {
        title: "Total Providers",
        value: totalProviders,
        helper: "All providers onboarded",
        icon: Users,
        accent: "bg-cyan-100 text-cyan-600 dark:bg-cyan-900/30 dark:text-cyan-300",
      },
      {
        title: "Active Providers",
        value: activeCount,
        helper: `${activeRate}% active rate`,
        icon: CheckCircle2,
        accent: "bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-300",
      },
      {
        title: "Average Rating",
        value: averageRating.toFixed(1),
        helper: "Out of 5 stars",
        icon: Star,
        accent: "bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-300",
      },
      {
        title: "Jobs Completed",
        value: totalJobs,
        helper: "Lifetime jobs finished",
        icon: Briefcase,
        accent: "bg-sky-100 text-sky-600 dark:bg-sky-900/30 dark:text-sky-300",
      },
    ],
    [activeCount, activeRate, averageRating, totalJobs, totalProviders]
  );

  const statusBreakdown = useMemo(
    () => [
      {
        label: "Active",
        value: activeCount,
        percent: totalProviders ? Math.round((activeCount / totalProviders) * 100) : 0,
        gradient: "from-emerald-400 to-emerald-600",
        status: "active" as ProviderStatus,
      },
      {
        label: "Inactive",
        value: inactiveCount,
        percent: totalProviders ? Math.round((inactiveCount / totalProviders) * 100) : 0,
        gradient: "from-slate-400 to-slate-600",
        status: "inactive" as ProviderStatus,
      },
      {
        label: "Suspended",
        value: suspendedCount,
        percent: totalProviders ? Math.round((suspendedCount / totalProviders) * 100) : 0,
        gradient: "from-rose-400 to-rose-600",
        status: "suspended" as ProviderStatus,
      },
    ],
    [activeCount, inactiveCount, suspendedCount, totalProviders]
  );

  const topProviders = useMemo(
    () =>
      [...providers]
        .sort((a, b) => {
          if (b.rating === a.rating) {
            return b.completedJobs - a.completedJobs;
          }
          return b.rating - a.rating;
        })
        .slice(0, 4),
    [providers]
  );

  const recentJoiners = useMemo(
    () =>
      [...providers]
        .sort(
          (a, b) =>
            new Date(b.joinedDate).getTime() - new Date(a.joinedDate).getTime()
        )
        .slice(0, 4),
    [providers]
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
        <div>
          <h2 className="text-2xl font-semibold tracking-tight">Provider Operations</h2>
          <p className="text-sm text-muted-foreground">
            Monitor team performance, review workload, and identify top performers across your service network.
          </p>
        </div>
        <div className="flex flex-wrap gap-2">
          <Link href="/admin/providers/manage">
            <Button className="text-white" style={{ background: "linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)" }}>
              <UserCog className="mr-2 h-4 w-4" /> Manage Providers
            </Button>
          </Link>
          <Link href="/admin/bookings">
            <Button variant="outline" className="gap-2">
              <ArrowUpRight className="h-4 w-4" /> View Upcoming Jobs
            </Button>
          </Link>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        {stats.map((stat) => {
          const Icon = stat.icon;
          return (
            <Card key={stat.title} className="overflow-hidden">
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  {stat.title}
                </CardTitle>
                <div className={`rounded-full p-2 ${stat.accent}`}>
                  <Icon className="h-4 w-4" />
                </div>
              </CardHeader>
              <CardContent>
                <div className="text-3xl font-semibold tracking-tight">{stat.value}</div>
                <p className="mt-1 text-sm text-muted-foreground">{stat.helper}</p>
              </CardContent>
            </Card>
          );
        })}
      </div>

      <div className="grid gap-4 lg:grid-cols-3">
        <Card className="lg:col-span-2">
          <CardHeader>
            <div className="flex items-center justify-between">
              <div>
                <CardTitle>Performance Snapshot</CardTitle>
                <p className="text-sm text-muted-foreground">
                  Ratings and workload distribution across the provider team.
                </p>
              </div>
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <TrendingUp className="h-4 w-4" /> Avg rating {averageRating.toFixed(1)} / 5
              </div>
            </div>
          </CardHeader>
          <CardContent className="space-y-5">
            <div className="grid gap-4 md:grid-cols-2">
              {topProviders.map((provider) => (
                <div
                  key={provider.id}
                  className="rounded-xl border border-border p-4 transition-colors hover:bg-muted/40"
                >
                  <div className="flex items-center gap-3">
                    <Avatar className="h-10 w-10">
                      <AvatarFallback>{getInitials(provider.name)}</AvatarFallback>
                    </Avatar>
                    <div className="flex-1">
                      <div className="flex items-center justify-between">
                        <p className="text-sm font-semibold text-foreground">{provider.name}</p>
                        <Badge variant="secondary" className="flex items-center gap-1">
                          <Star className="h-3 w-3 fill-yellow-400 text-yellow-400" />
                          {provider.rating.toFixed(1)}
                        </Badge>
                      </div>
                      <p className="text-xs text-muted-foreground">{provider.specialization}</p>
                    </div>
                  </div>
                  <div className="mt-4 space-y-2">
                    <div className="flex items-center justify-between text-xs text-muted-foreground">
                      <span>Jobs Completed</span>
                      <span className="font-medium text-foreground">{provider.completedJobs}</span>
                    </div>
                    <Progress value={Math.min((provider.rating / 5) * 100, 100)} />
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Status Breakdown</CardTitle>
            <p className="text-sm text-muted-foreground">
              Track the distribution of providers by current availability status.
            </p>
          </CardHeader>
          <CardContent className="space-y-4">
            {statusBreakdown.map((item) => (
              <div key={item.label} className="space-y-1.5">
                <div className="flex items-center justify-between text-sm">
                  <span className="font-medium text-foreground">{item.label}</span>
                  <span className="text-muted-foreground">{item.value} ({item.percent}%)</span>
                </div>
                <div className="h-2 overflow-hidden rounded-full bg-muted">
                  <div
                    className={`h-full bg-gradient-to-r ${item.gradient}`}
                    style={{ width: `${item.percent}%` }}
                  />
                </div>
                <div className="text-xs text-muted-foreground">{getStatusBadge(item.status)}</div>
              </div>
            ))}
          </CardContent>
        </Card>
      </div>

      <div className="grid gap-4 lg:grid-cols-2">
        <Card>
          <CardHeader>
            <CardTitle>Recent Joiners</CardTitle>
            <p className="text-sm text-muted-foreground">
              Keep an eye on onboarding progress for newly added service providers.
            </p>
          </CardHeader>
          <CardContent className="space-y-4">
            {recentJoiners.map((provider) => (
              <div key={provider.id} className="flex items-start justify-between rounded-lg border border-border p-3">
                <div className="flex items-start gap-3">
                  <Avatar className="h-9 w-9">
                    <AvatarFallback>{getInitials(provider.name)}</AvatarFallback>
                  </Avatar>
                  <div>
                    <p className="text-sm font-semibold text-foreground">{provider.name}</p>
                    <p className="text-xs text-muted-foreground">Joined {formatDate(provider.joinedDate)}</p>
                    <p className="mt-1 text-xs text-muted-foreground">{provider.specialization}</p>
                  </div>
                </div>
                {getStatusBadge(provider.status)}
              </div>
            ))}
            {recentJoiners.length === 0 && (
              <p className="text-sm text-muted-foreground">No providers have been added recently.</p>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Operational Insights</CardTitle>
            <p className="text-sm text-muted-foreground">
              Quick pulse on provider network health and utilization.
            </p>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between rounded-lg bg-gradient-to-r from-cyan-500/10 to-blue-500/10 p-4">
              <div>
                <p className="text-sm font-medium text-foreground">Network Coverage</p>
                <p className="text-xs text-muted-foreground">Active providers across all services</p>
              </div>
              <div className="text-2xl font-semibold text-cyan-600 dark:text-cyan-400">{activeRate}%</div>
            </div>
            <div className="flex items-center justify-between rounded-lg bg-gradient-to-r from-amber-500/10 to-orange-500/10 p-4">
              <div>
                <p className="text-sm font-medium text-foreground">Quality Index</p>
                <p className="text-xs text-muted-foreground">Based on rating trends</p>
              </div>
              <div className="text-2xl font-semibold text-amber-600 dark:text-amber-400">{averageRating.toFixed(1)}/5</div>
            </div>
            <div className="flex items-center justify-between rounded-lg bg-gradient-to-r from-rose-500/10 to-red-500/10 p-4">
              <div>
                <p className="text-sm font-medium text-foreground">At-Risk Providers</p>
                <p className="text-xs text-muted-foreground">Review engagement for suspended accounts</p>
              </div>
              <div className="text-2xl font-semibold text-rose-600 dark:text-rose-400">{suspendedCount}</div>
            </div>
            <div className="flex items-center justify-between rounded-lg bg-gradient-to-r from-emerald-500/10 to-green-500/10 p-4">
              <div>
                <p className="text-sm font-medium text-foreground">Average Workload</p>
                <p className="text-xs text-muted-foreground">Jobs per active provider</p>
              </div>
              <div className="text-2xl font-semibold text-emerald-600 dark:text-emerald-400">
                {activeCount ? Math.round(totalJobs / activeCount) : 0}
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default ProvidersDashboard;
